INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (1, 'default', 1, 'God Proposes College::.. Home Page', 'page/god-proposes-college-home-page', 'page', 'god-proposes-college-home-page', '', '', '', '', '<div class=\"service-inner\">\r\n<div class=\"container\">\r\n<div class=\"row\">\r\n<div class=\"col-md-4 col-sm-4 service-box\">\r\n<div class=\"service-box-content\">\r\n<h3><a href=\"#\">Quality Education</a></h3>\r\n\r\n<p>Students\' Imaginagion and Creativivity Development.</p>\r\n\r\n<div class=\"service-box-icon\"><img src=\"https://demo.smart-school.in/uploads/gallery/media/scholarship-icon.png\" /></div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"col-md-4 col-sm-4 service-box\">\r\n<div class=\"service-box-content\">\r\n<h3><a href=\"#\">Books & Library</a></h3>\r\n\r\n<p>Well Stocked Library with Automated Library Mgt System.</p>\r\n\r\n<div class=\"service-box-icon\"><img src=\"https://demo.smart-school.in/uploads/gallery/media/book-icon.png\" /></div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"col-md-4 col-sm-4 service-box\">\r\n<div class=\"service-box-content\">\r\n<h3><a href=\"#\">Certified Teachers</a></h3>\r\n\r\n<p>Well Qualified, Seasoned, Dedicated Teachers..</p>\r\n\r\n<div class=\"service-box-icon\"><img src=\"https://demo.smart-school.in/uploads/gallery/media/teacher-icon.png\" /></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"container spacet40\">\r\n<div class=\"row\">\r\n<p>&nbsp;</p>\r\n</div>\r\n</div>', '0000-00-00', 1, NULL, 'no', '2022-01-15 07:38:21');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (2, 'default', 0, 'Complaints and Recommendations', 'page/complaints-and-recommendations', 'page', 'complaints-and-recommendations', 'Complain form', '                                                                                                                                                                                    complain form                                                                                                                                                                                                                                ', 'complain form', '', '<p><span style=\"font-family:roboto,sans-serif; font-size:14px\">Please fill the form below to submit any form of complaints or recommendations to the school authority.</span></p>\r\n\r\n<p>[form-builder:complain]</p>', '0000-00-00', 1, NULL, 'no', '2022-01-09 07:35:57');
