INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (89, 'manual', 0, 'Principal Message', 'page/principal-message', 'page', 'principal-message', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"col-md-6 col-sm-6\"><img alt=\"\" src=\"data:image/png;base64,\" /></div>\r\n\r\n<div class=\"col-md-6 col-sm-6\">\r\n<h2>Message From Principal</h2>\r\n\r\n<p><span style=\"color:rgb(46, 46, 46); font-family:open sans,sans-serif; font-size:17px\">Our mission is to provide cost-effective world class education in a safe, peaceful, disciplined and intellectually stimulating environment. Our team of dedicated and internationally trained teachers purpose to raise fine, well-rounded, well-educated, well-cultured, respectable, God-fearing ladies and gentlemen who will make huge contributions towards the promotion and protection of human dignity in our society.</span></p>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2022-01-15 07:45:35');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (90, 'manual', 0, 'School Management', 'page/school-management', 'page', 'school-management', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12 col-sm-12\">\r\n<h4>School Management</h4>\r\n\r\n<p>School Management System is a multipurpose school management software which is used for all administration, management and learning related activities. Use School management information system to manage students, teachers, employees, courses and all the system and process related to running your institute efficiently. Online school management system delivers premier online fee payment, registration and data management tools for schools, administrators, finance personnel and students. It\'s simple, web-based technologies help improve efficiency and reduce costs associated with managing school registration, budgeting, fund accounting, fundraising, after-school care, and more. Online school management solution streamlines school registration with automatic back-office administration, campus recreation and intramurals, facilities, student data, school accounting, web site content management and enables educational institutions to focus on teaching and enriching the lives of students.</p>\r\n\r\n<ol type=\"1\">\r\n	<li>User friendly Interface</li>\r\n	<li>School Detail Management</li>\r\n	<li>Registration /Admission Management</li>\r\n	<li>Fee Category Management</li>\r\n	<li>Student Fee Management (Fee Detail, Fee Receipt etc.)</li>\r\n	<li>Student Administration</li>\r\n	<li>Class/div Management</li>\r\n	<li>ID Cards Printing</li>\r\n	<li>Student Information Management</li>\r\n	<li>Leave & Attendance Management</li>\r\n	<li>Advance Search for Student Information</li>\r\n	<li>Lesson Planning</li>\r\n	<li>Time Table</li>\r\n	<li>Examination & Evaluation Process</li>\r\n	<li>Online Exam</li>\r\n	<li>SMS Alerts to Students</li>\r\n	<li>Transfer Certificate Management</li>\r\n	<li>Reports Management (Daily Collection, Fee Outstanding, Scroll Sheet etc.)</li>\r\n	<li>Transport Management</li>\r\n	<li>Transport Fee Collection Management</li>\r\n	<li>Visitor Management</li>\r\n	<li>Compliant Management</li>\r\n	<li>Employee Registration Management</li>\r\n	<li>Employee Attendance Management</li>\r\n	<li>Holiday Management</li>\r\n	<li>Salary Structure Management</li>\r\n	<li>Employee Salary Management</li>\r\n	<li>Employee Attendance and Salary Reports</li>\r\n	<li>Secure and Reliable</li>\r\n	<li>Many more Feature Available</li>\r\n</ol>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 11:58:41');
