INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (92, 'manual', 0, 'Approach', 'page/approach', 'page', 'approach', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"col-md-8 col-sm-8\">\r\n<h2 class=\"pb20\">Singular Focus; Multiple Intelligences</h2>\r\n\r\n<p>Mount Carmel School , Baghmugalia, Bhopal is a recognized unaided Christian minority institution founded in the year 1999, affiliated to the Council for the Indian School Certificate Examination , New Delhi (School Code Mp023). The School prepares its students for the ICSE and the ISC Examination at X and XII Level respectively.</p>\r\n\r\n<p>The school is managed by the Sisters of the Congregation of the Mother of Carmel . The Congregation is a religious and charitable organization and its members offer their dedicated and selfless service for the intellectual , moral and aesthetic development of the people in the vicinity.</p>\r\n</div>\r\n<!--./col-md-6-->\r\n\r\n<div class=\"col-md-4 col-sm-4\">\r\n<div class=\"about_img\"><img class=\"img-responsive img-rounded\" src=\"https://demo.smart-school.in/uploads/gallery/media/about.jpg\" /></div>\r\n</div>\r\n<!--./col-md-6--></div>\r\n<!--./row--></div>\r\n<!--./container-->\r\n\r\n<section class=\"bggray fullwidth\">\r\n<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12 whitebox\">\r\n<div class=\"col-lg-3 col-md-3 col-sm-3\"><img class=\"img-responsive img-rounded\" src=\"https://demo.smart-school.in/uploads/gallery/media/classrooms.jpg\" /></div>\r\n\r\n<div class=\"col-lg-9 col-md-9 col-sm-9\">\r\n<h2>Teaching Methodology</h2>\r\n\r\n<p class=\"text-justify\">The school is managed by the Sisters of the Congregation of the Mother of Carmel . The Congregation is a religious and charitable organization and its members offer their dedicated and selfless service for the intellectual , moral and aesthetic development of the people in the vicinity. The school is managed by the Sisters of the Congregation of the Mother of Carmel . The Congregation is a religious and charitable organization and its members offer their dedicated and selfless service for the intellectual , moral and aesthetic development of the people in the vicinity.</p>\r\n</div>\r\n</div>\r\n<!--./col-md-4--><!--./col-md-4--></div>\r\n<!--./row--></div>\r\n<!--./container--></section>\r\n\r\n<div class=\"container spaceb60 spacet60 text-center\">\r\n<div class=\"row\">\r\n<div class=\"col-md-8 col-md-offset-2\">\r\n<h2>Professional Learning Program</h2>\r\n\r\n<p class=\"text-justify\">The School has partnered with Learning Forward India, whereby Educators undertake structured Training sessions and self-directed professional learning.</p>\r\n\r\n<p class=\"text-justify\">The Professional Learning Program (PLP) aligns with the mission of Learning Forward (www.learningforward.org), the world\'s largest body of individual educators, with a vision of excellent teaching and learning every day. The Iconic School, in collaboration with The Learning Forward India Academy promotes building the capacity of leaders to establish and sustain highly effective professional learning. Professional learning means a comprehensive, sustained and intensive approach to improving teachers’ and principals’ effectiveness in raising student achievement.</p>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 11:59:18');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (93, 'manual', 0, 'Pre Primary', 'page/pre-primary', 'page', 'pre-primary', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"blue-box1\">\r\n<div class=\"row\">\r\n<div class=\"col-md-4 col-sm-6\">\r\n<div class=\"around40\"><img alt=\"\" height=\"75\" src=\"https://demo.smart-school.in/uploads/gallery/media/iconic-f17-1.png\" width=\"75\" />\r\n<h2>Involve</h2>\r\n\r\n<p class=\"blue-text\">Pre-Primary</p>\r\n\r\n<p>Mount Carmel School , Baghmugalia, Bhopal is a recognized unaided Christian minority institution founded in the year 1999, affiliated to the Council for the Indian School Certificate Examination , New Delhi (School Code Mp023). The School prepares its students for the ICSE and the ISC Examination at X and XII Level respectively. The school is managed by the Sisters of the Congregation of the Mother of Carmel</p>\r\n</div>\r\n</div>\r\n\r\n<div class=\"col-md-8 col-sm-6\"><img class=\"img-responsive\" src=\"https://demo.smart-school.in/uploads/gallery/media//classrooms.jpg\" /></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 12:02:23');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (94, 'manual', 0, 'Primary', 'page/primary', 'page', 'primary', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"blue-box1\">\r\n<div class=\"row\">\r\n<div class=\"col-md-8 col-sm-6\"><img class=\"img-responsive\" src=\"https://demo.smart-school.in/uploads/gallery/media//classrooms.jpg\" /></div>\r\n\r\n<div class=\"col-md-4 col-sm-6\">\r\n<div class=\"around40\"><img alt=\"\" height=\"75\" src=\"https://demo.smart-school.in/uploads/gallery/media/iconic-f17-1.png\" width=\"75\" />\r\n<h2>Instill</h2>\r\n\r\n<p class=\"blue-text\">Pre-Primary</p>\r\n\r\n<p>Mount Carmel School, Baghmugalia, Bhopal is a recognized unaided Christian minority institution founded in the year 1999, affiliated to the Council for the Indian School Certificate Examination , New Delhi (School Code Mp023). The School prepares its students for the ICSE and the ISC Examination at X and XII Level respectively. The school is managed by the Sisters of the Congregation of the Mother of Carmel</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 12:03:23');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (95, 'manual', 0, 'Sports', 'page/sports', 'page', 'sports', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"col-md-5 col-sm-5\"><img class=\"img-responsive\" src=\"https://demo.smart-school.in/uploads/gallery/media//classrooms.jpg\" /></div>\r\n\r\n<div class=\"col-md-7 col-sm-7\">\r\n<h2>Sports</h2>\r\n\r\n<p>Mount Carmel School , Baghmugalia, Bhopal is a recognized unaided Christian minority institution founded in the year 1999, affiliated to the Council for the Indian School Certificate Examination , New Delhi (School Code Mp023). The School prepares its students for the ICSE and the ISC Examination at X and XII Level respectively. The school is managed by the Sisters of the Congregation of the Mother of Carmel</p>\r\n\r\n<p>Mount Carmel School , Baghmugalia, Bhopal is a recognized unaided Christian minority institution founded in the year 1999, affiliated to the Council for the Indian School Certificate Examination , New Delhi (School Code Mp023). The School prepares its students for the ICSE and the ISC Examination at X and XII Level respectively. The school is managed by the Sisters of the Congregation of the Mother of Carmel</p>\r\n</div>\r\n\r\n<div class=\"col-sm-12 col-md-12 text-justify sports pt20\">\r\n<h2>Sports for Icons - <b>\"Right to play & play for all\"</b></h2>\r\n\r\n<p>A healthy mind resides in a healthy body. Games and sports education are not only significant for triumph in the student life but it is a key to achievement in every stride of life. The Mount School believes in \"Right to play & play for all\". The school sports structure is developed to cater to various needs of the child. If sports are inculcated from a very young age, it helps build character and discipline. It gives students the confidence to trust their own individuality.</p>\r\n\r\n<h2>For Kinder Garten – SPORTS SPROUTS</h2>\r\n\r\n<p>In this, natural curiosity and interaction with the environment stimulate the growth of motor activity which helps students to make a strong foundation for the sports. The body movement and coordination of the child is tapped through various locomotor, non-locomotor and manipulative activities. For the little icons, skill based sports like skating and gymnastic are offered.</p>\r\n\r\n<h2>For Primary - ALL-ROUNDER</h2>\r\n\r\n<p>The School provides opportunities to students to have the benefit of maximum sports with enjoyment. Education on fundamentals of every sports activity is imparted wherein the students get an experience of various sports like football, cricket, skating, swimming, athletics, etc. This varied experience enables students to identify a sport of their choice and excel in the same.</p>\r\n\r\n<h2>For Middle– SPECIALISATION</h2>\r\n\r\n<p>At this stage, sports programme encourages the students to excel in one sport, so that they are able to chip in and execute well in Intramural and Extramural competitions. Sports offered for the specialization include basketball, cricket and football.</p>\r\n\r\n<p>We, at Mount, believe that as long as the icons are involved in sports activities, all their senses, the locomotor system and intellectual capacities are engaged. By playing sports, child becomes stronger, physically as well as mentally. Above all, they learn to overcome obstacles and challenges in real life situations.</p>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 12:03:45');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (96, 'manual', 0, 'Student Council', 'page/student-council', 'page', 'student-council', '', '', '', '', '<div class=\"container spacet50 spaceb50\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12 col-sm-12 text-justify\">\r\n<h2>Student Council</h2>\r\n\r\n<p>Mount Carmel School , Baghmugalia, Bhopal is a recognized unaided Christian minority institution founded in the year 1999, affiliated to the Council for the Indian School Certificate Examination , New Delhi (School Code Mp023). The School prepares its students for the ICSE and the ISC Examination at X and XII Level respectively.</p>\r\n\r\n<ol class=\"list-1\">\r\n	<li>School&nbsp; diary&nbsp; is to be brought to school daily without fail.</li>\r\n	<li>Students should come to school in complete school uniform, on all school days ( including PTM).</li>\r\n	<li>Punctuality &nbsp;a must and late comers will be suitably checked with corrective measures.</li>\r\n	<li>No mobile phone is to be brought to school for what so ever reason. The set will be confiscated and very strict action will be taken against the user. The set will be returned only at the end of the<br />\r\n	&nbsp;&nbsp;session .</li>\r\n	<li>Students are discouraged to come to school by private vans using gas kits or over loaded.</li>\r\n	<li>85 % attendance is a must for every student.</li>\r\n	<li>A pupil who uses unfair means during examinations will be given zero in the subject and repetition of the same shall lead to dismissal.</li>\r\n	<li>Parents / guardians can meet the principal in her office from 9:00 am to 10:00 am. on all school<br />\r\n	working days.</li>\r\n	<li>Parents / guardians should meet teachers only on PTM or with appointment in special cases.</li>\r\n	<li>It is compulsory for all students to participate in sports, games and co-curricular&nbsp; activities of<br />\r\n	the school .</li>\r\n	<li>In case of accidents, school will provide only first aid; other related expenses will be borne by&nbsp;<br />\r\n	Parents / guardians.</li>\r\n</ol>\r\n\r\n<div class=\"col-md-12\">\r\n<h2>Student Council 2018-19</h2>\r\n\r\n<table class=\"table table-striped table-bordered\">\r\n	<tbody>\r\n		<tr>\r\n			<td>School Captain</td>\r\n			<td>Yashi Agrawal</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Sports Captain</td>\r\n			<td>Krishna Soni</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Editor-in-Chief</td>\r\n			<td>Tanisha Agrawal</td>\r\n		</tr>\r\n		<tr>\r\n			<th colspan=\"12\">\r\n			<center>\r\n			<h3>Houses</h3>\r\n			</center>\r\n			</th>\r\n		</tr>\r\n		<tr>\r\n			<td>Jade House Captain</td>\r\n			<td>Naman Sinha</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Jade Vice-House Captain</td>\r\n			<td>Kartik Marale</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Topaz House Captain</td>\r\n			<td>Ansh Budhwani</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Topaz Vice-House Captain</td>\r\n			<td>Aparna Kushwaha</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Sapphire House Captain</td>\r\n			<td>Alankriti Dube</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Sapphire Vice-House Captain</td>\r\n			<td>Prakhar Verma</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Ruby House Captain</td>\r\n			<td>Niyati Sinha</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Ruby Vice-House Captain</td>\r\n			<td>Hiren Jain</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 12:04:19');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (97, 'manual', 0, 'Houses & Mentoring', 'page/houses-mentoring', 'page', 'houses-mentoring', '', '', '', '', '<div class=\"container spacet50 spaceb50\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12 col-sm-12 text-justify\">\r\n<h3>School House System and Mentoring System</h3>\r\n\r\n<p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book.Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h3>Grade 1 to 4 – Mentoring System</h3>\r\n\r\n<p>The school is managed by the Sisters of the Congregation of the Mother of Carmel . The Congregation is a religious and charitable organization and its members offer their dedicated and selfless service for the intellectual , moral and aesthetic development of the people in the vicinity</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h3>Grade 5 onwards – House System</h3>\r\n\r\n<p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book</p>\r\n</div>\r\n</div>\r\n</div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 12:04:43');
INSERT INTO `front_cms_pages` (`id`, `page_type`, `is_homepage`, `title`, `url`, `type`, `slug`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `description`, `publish_date`, `publish`, `sidebar`, `is_active`, `created_at`) VALUES (98, 'manual', 0, 'Career Counselling', 'page/career-counselling', 'page', 'career-counselling', '', '', '', '', '<div class=\"container spaceb60 spacet60\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12 whitebox\">\r\n<div class=\"col-lg-6 col-md-6 col-sm-12\"><img class=\"img-responsive img-rounded\" src=\"https://demo.smart-school.in/uploads/gallery/media/classrooms.jpg\" /></div>\r\n\r\n<div class=\"col-lg-6 col-md-6 col-sm-12\">\r\n<h2>Career Counselling</h2>\r\n\r\n<p class=\"text-justify\">The school is managed by the Sisters of the Congregation of the Mother of Carmel . The Congregation is a religious and charitable organization and its members offer their dedicated and selfless service for the intellectual , moral and aesthetic development of the people in the vicinity. The school is managed by the Sisters of the Congregation of the Mother of Carmel . The Congregation is a religious and charitable organization and its members offer their dedicated and selfless service for the intellectual , moral and aesthetic development of the people in the vicinity.</p>\r\n\r\n<p>Counselling activities encompass the following :</p>\r\n\r\n<ul class=\"square\">\r\n	<li>Helping students to identify their areas of interest and aptitude.</li>\r\n	<li>Guiding students about application processes in India and abroad.</li>\r\n	<li>Providing updated information about various institutions, courses and careers.</li>\r\n	<li>Giving sustained support in the admission process that includes collating and dispatching transcripts, writing out recommendation letters, predicted grades and school profiles and helping with the Personal Statements to be submitted.</li>\r\n</ul>\r\n</div>\r\n</div>\r\n<!--./col-md-4--><!--./col-md-4--></div>\r\n<!--./row--></div>', '0000-00-00', 0, NULL, 'no', '2019-05-04 12:05:12');
