INSERT INTO `front_cms_programs` (`id`, `type`, `slug`, `url`, `title`, `date`, `event_start`, `event_end`, `event_venue`, `description`, `is_active`, `created_at`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `publish_date`, `publish`, `sidebar`) VALUES (19, 'events', 'school-band-troupe', 'read/school-band-troupe', 'School Band Troupe', NULL, '2019-04-10', '2019-04-10', '', '<p open=\"\" style=\"line-height: 22px; font-family: \">MCRS hosts several competitions for fostering the talents and skills of students. The main competitions are as follows:</p>\r\n\r\n<h2 open=\"\" style=\"font-size: 20px; color: rgb(139, 22, 24); font-weight: lighter; margin: 5px 0px 10px; font-family: \">Literary Fest</h2>\r\n\r\n<p open=\"\" style=\"line-height: 22px; font-family: \">To develop the literary skills of students the Literary Fest is conducted every academic year. Competitions such as essay writing, debates, group discussions, elocutions and many more are conducted during the Literary Fest. Competitions are conducted for juniors and seniors house wise. &lsquo;Literary Genius Award&rsquo; goes to the participant who has scored the top marks.<strong><em>&nbsp;&lsquo;</em></strong>Best House-Literary&rsquo;- Rolling trophy presented to the house that scores the highest point in Literary Fest.</p>', 'no', '2019-05-01 13:17:20', '', '', '', 'https://demo.smart-school.in/uploads/gallery/media/gal31.jpg', '0000-00-00', '0', NULL);
INSERT INTO `front_cms_programs` (`id`, `type`, `slug`, `url`, `title`, `date`, `event_start`, `event_end`, `event_venue`, `description`, `is_active`, `created_at`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `publish_date`, `publish`, `sidebar`) VALUES (20, 'events', 'competitions', 'read/competitions', 'Competitions', NULL, '2019-04-10', '2019-04-10', '', '<p><span open=\"\" style=\"font-family: \">To develop the literary skills of students the Literary Fest is conducted every academic year. Competitions such as essay writing, debates, group discussions, elocutions and many more are conducted during the Literary Fest. Competitions are conducted for juniors and seniors house wise. &lsquo;Literary Genius Award&rsquo; goes to the participant who has scored the top marks.</span><strong open=\"\" style=\"font-family: \"><em>&nbsp;&lsquo;</em></strong><span open=\"\" style=\"font-family: \">Best House-Literary&rsquo;- Rolling trophy presented to the house that scores the highest point in Literary Fest.</span></p>\r\n\r\n<p><span open=\"\" style=\"font-family: \">Students get an opportunity to bring out the artist them. Competitions are held on various art forms, such as dance items, music, mime, fancy dress etc. Competitions are all conducted house wise. The &lsquo;Kalathilakam&rsquo; and &lsquo;Kalaprathibha&rsquo; awards are presented to the girl and boy participant respectively, who scores the top points for the Arts Fest.</span><strong open=\"\" style=\"font-family: \"><em>&nbsp;&lsquo;</em></strong><span open=\"\" style=\"font-family: \">Best House -Arts t&rsquo;- Rolling trophy is presented to the house that scores the highest point in Arts Fest.</span></p>', 'no', '2019-04-30 10:39:15', '', '', '', 'https://demo.smart-school.in/uploads/gallery/media/gal43.jpg', '0000-00-00', '0', NULL);
INSERT INTO `front_cms_programs` (`id`, `type`, `slug`, `url`, `title`, `date`, `event_start`, `event_end`, `event_venue`, `description`, `is_active`, `created_at`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `publish_date`, `publish`, `sidebar`) VALUES (21, 'events', 'working-days-time-schedule', 'read/working-days-time-schedule', 'Working Days & Time Schedule', NULL, '2019-04-10', '2019-04-10', '', '<p style=\"margin: 4px 0px; text-align: left;\">The school Administration Office works from Monday to Saturday, from 8:00 am to 4:00pm.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">On days such as Xmas, Onam, Good Friday the school Administration Office will not function.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">The classes are held on all weekdays from Monday to Friday, from 8:30 am to 2:30 pm.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">Supervisory classes are conducted on working days intimated for the senior classes from 3:00 pm to 6:00 pm.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">The summer vacation for the students will begin on the first of April and ends on the last of May, unless otherwise specified.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">Normally 10 days are given as holidays for Onam and Xmas.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">The school will work on Patriotic days so as to celebrate these days.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">School will remain closed for the students on the days the teachers have teachers training programmes.</p>\r\n\r\n<p style=\"margin: 4px 0px; text-align: left;\">The time schedule may vary on the days of functions or competitions.</p>', 'no', '2019-04-30 10:38:37', '', '', '', 'https://demo.smart-school.in/uploads/gallery/media/gal41.jpg', '0000-00-00', '0', NULL);
INSERT INTO `front_cms_programs` (`id`, `type`, `slug`, `url`, `title`, `date`, `event_start`, `event_end`, `event_venue`, `description`, `is_active`, `created_at`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `publish_date`, `publish`, `sidebar`) VALUES (22, 'events', 'student-council', 'read/student-council', 'Student Council', NULL, '2019-04-10', '2019-04-10', '', '<p open=\"\" style=\"line-height: 22px;\">The Student Council of MCRS is an association of the representatives of the students. Guided by the Student Council Supervisor, the School Leader heads the Student Council. The Head Girl and Head Boy of the school, assists the School Leader. The Secretaries of all the Students Clubs, the House Captains and the Vice Captains together form the members of the Student Council.</p>\r\n\r\n<p open=\"\" style=\"line-height: 22px;\">It is considered as an honor by the students to be a member of the Student Council. Every academic year witnesses the selection of a new Student Council. The Student Council is formed in the very first month of every academic year, and formally inaugurated in the same month. The formal introduction of Student Council Members is done at the inaugural function followed by their badging and Oath taking ceremony.</p>\r\n\r\n<p open=\"\" style=\"line-height: 22px;\">The Student Council members are honored for their deeds on the Annual Day. On the Annul Day,&nbsp;<strong><em>&lsquo;</em></strong>Student Council Member of the Year&rsquo; is awarded to that Student Council Member who scores the highest point in performing his/her duties and responsibilities.</p>', 'no', '2019-04-30 10:37:52', '', '', '', 'https://demo.smart-school.in/uploads/gallery/media/gal40.jpg', '0000-00-00', '0', NULL);
INSERT INTO `front_cms_programs` (`id`, `type`, `slug`, `url`, `title`, `date`, `event_start`, `event_end`, `event_venue`, `description`, `is_active`, `created_at`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `publish_date`, `publish`, `sidebar`) VALUES (23, 'events', 'school-tours', 'read/school-tours', 'School Tours', NULL, '2019-04-10', '2019-04-10', '', '<p open=\"\" style=\"line-height: 22px;\">Study Tours, field trips and excursions are conducted separately, for the students of the Junior School, Primary, Middle school, Secondary and Senior Secondary during the academic year, for which attendance is mandatory. These tours provide the pupils with opportunity for visiting places of historical or geographical or national importance, or even subject importance. These educational tours encourage them to pick up values of social interaction. It is a part of training on social values.</p>\r\n\r\n<p open=\"\" style=\"line-height: 22px;\">The school also organizes every academic year a tour for our staff to provide them a day of fun and joy.</p>', 'no', '2019-04-30 10:37:11', '', '', '', 'https://demo.smart-school.in/uploads/gallery/media/gal39.jpg', '0000-00-00', '0', NULL);
INSERT INTO `front_cms_programs` (`id`, `type`, `slug`, `url`, `title`, `date`, `event_start`, `event_end`, `event_venue`, `description`, `is_active`, `created_at`, `meta_title`, `meta_description`, `meta_keyword`, `feature_image`, `publish_date`, `publish`, `sidebar`) VALUES (25, 'notice', 'school-software-training', 'read/school-software-training', 'School Software training', '2022-01-11', NULL, NULL, NULL, '<h4 xss=\"removed\">School Software training resumes on this day and date to meet the parents on the school digitization will be communicated shortly</h4>', 'no', '2022-01-08 09:36:29', '', '', '', '', '0000-00-00', '0', NULL);
