INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (231, 6, 89, 'singlechoice', 'medium', 7, 0, NULL, 'The body responsible for the implementation of law is', 'Judiciary', 'Legislature', 'Executive', 'Court', '', 'opt_c', '2022-03-04 04:54:11', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (232, 6, 90, 'singlechoice', 'medium', 8, 0, NULL, 'Which of the following is not a feature of a state', 'Sovereignty', 'Government', 'Mass media', 'Territory', '', 'opt_c', '2022-03-04 04:55:54', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (233, 6, 90, 'singlechoice', 'medium', 8, 0, NULL, 'Government maintain law and order through the following except', 'Police', 'Immigration', 'The legislature', 'Prison service', '', 'opt_b', '2022-03-04 04:58:22', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (234, 6, 91, 'singlechoice', 'medium', 9, 0, NULL, 'In a constitutional monarchy,the king or queen is refer to as', 'Ceremonial head', 'Political head', 'Constitutional head', 'Democratic leader', '', 'opt_a', '2022-03-04 05:00:53', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (235, 6, 91, 'singlechoice', 'medium', 9, 0, NULL, 'Which of the following is a fundamental rights', 'Right to life', 'Right to education', 'Right to criticize government', 'Public office', '', 'opt_a', '2022-03-04 05:02:48', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (236, 5, 68, 'singlechoice', 'medium', 7, 0, NULL, 'The land and sea and vegetation were created on the', 'First day', 'Second day', 'Third day', 'Fifth day', '', 'opt_c', '2022-03-04 05:08:44', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (237, 5, 68, 'singlechoice', 'medium', 7, 0, NULL, 'God blessed the seventh day and hallowed it because it marked the day that He', 'Completed His work of creation', 'Handed over the earth to Adam', 'Saw all His created work as perfect', 'Rested from His work of creation', '', 'opt_d', '2022-03-04 05:12:46', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (238, 5, 69, 'singlechoice', 'medium', 8, 0, NULL, 'Which of the following was not part of the honour done to joseph when pharaoh made him a ruler in Egypt', 'Joseph was made to address the people', 'The land Goshen was given to joseph', 'Joseph was addressed in garments of fine linen', 'A gold chain was put around Joseph\'s neck', '', 'opt_b', '2022-03-04 05:17:52', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (239, 5, 69, 'singlechoice', 'medium', 8, 0, NULL, 'What was Moses reaction when God called him to liberate his people from Egypt', 'He was afraid of being punished for his previous offence', 'His people would think he was too young to lead them', 'His people would not listen to him', 'His father in law would not allow him to go', '', 'opt_c', '2022-03-04 05:22:38', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (240, 5, 70, 'singlechoice', 'medium', 9, 0, NULL, 'God led the israelites in the wilderness during the day in form of', 'Fire', 'Light', 'Cloud', 'Rainbow', '', 'opt_c', '2022-03-04 05:26:16', NULL);
INSERT INTO `questions` (`id`, `staff_id`, `subject_id`, `question_type`, `level`, `class_id`, `section_id`, `class_section_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `opt_e`, `correct`, `created_at`, `updated_at`) VALUES (241, 5, 70, 'singlechoice', 'medium', 9, 0, NULL, 'When Moses stayed away for too long on the mountain, the people of israel', 'Prayed and fasted', 'Embarked on farming', 'Returned to Egypt', 'Made and worshipped idol', '', 'opt_d', '2022-03-04 05:29:58', NULL);
