INSERT INTO `visitors_book` (`id`, `source`, `purpose`, `name`, `email`, `contact`, `id_proof`, `no_of_pepple`, `date`, `in_time`, `out_time`, `note`, `image`) VALUES (10, 'Online', 'quality monthly SEO plans', 'Mike Harris <a href=\'mailto:no-replybove@gmail.com\'>(no-replybove@gmail.com)</a>', 'no-replybove@gmail.com', '', '', 0, '2022-01-12', '', '', 'Hi there \r\n \r\nI have just took an in depth look on your  godproposescollege.com for its SEO Trend and saw that your website could use an upgrade. \r\n \r\nWe will improve your SEO metrics and ranks organically and safely, using only whitehat methods, while providing monthly reports and outstanding support. \r\n \r\nPlease check our plans here, we offer SEO at cheap rates. \r\nhttps://www.hilkom-digital.de/cheap-seo-packages/ \r\n \r\nStart enhancing your sales and leads with us, today! \r\n \r\n \r\nregards \r\nMike Harris\r\n \r\nHilkom Digital Team \r\nsupport@hilkom-digital.de (Sent from online front site)', '');
INSERT INTO `visitors_book` (`id`, `source`, `purpose`, `name`, `email`, `contact`, `id_proof`, `no_of_pepple`, `date`, `in_time`, `out_time`, `note`, `image`) VALUES (11, 'Online', 'Get more dofollow backlinks for godproposescollege.com', 'Mike Abramson <a href=\'mailto:no-replybove@gmail.com\'>(no-replybove@gmail.com)</a>', 'no-replybove@gmail.com', '', '', 0, '2022-01-17', '', '', 'Hello \r\n \r\nWe all know the importance that dofollow link have on any website`s ranks. \r\nHaving most of your linkbase filled with nofollow ones is of no good for your ranks and SEO metrics. \r\n \r\nBuy quality dofollow links from us, that will impact your ranks in a positive way \r\nhttps://www.digital-x-press.com/product/150-dofollow-backlinks/ \r\n \r\nBest regards \r\nMike Abramson\r\n \r\nsupport@digital-x-press.com (Sent from online front site)', '');
INSERT INTO `visitors_book` (`id`, `source`, `purpose`, `name`, `email`, `contact`, `id_proof`, `no_of_pepple`, `date`, `in_time`, `out_time`, `note`, `image`) VALUES (12, 'Online', 'SEMRUSH', 'Mike MacAdam <a href=\'mailto:no-replybove@gmail.com\'>(no-replybove@gmail.com)</a>', 'no-replybove@gmail.com', '', '', 0, '2022-01-19', '', '', 'Hello, \r\n \r\nThere is a new Boss in town. Semrush started dominating the SEO tools for some time already. So, why not get yourself backlinks that Semrush says are good, right? \r\n \r\nIn this plan, get backlinks that Semrush says are coming from quality domains, Domains which are having 5000+ ranking keywords \r\n \r\nMore info: \r\nhttps://www.seo-treff.de/product/semrush-backlinks/ \r\n \r\n \r\nThank you \r\nMike MacAdam\r\n \r\nsupport@seo-treff.de (Sent from online front site)', '');
